CREATE TABLE digitaltwinapp.transaction_codes (
    code  INTEGER      NOT NULL,
    label VARCHAR(100) NOT NULL,
    CONSTRAINT transaction_codes_pkey PRIMARY KEY (code)
);

-- Seeded from TX constants in src/types.ts (app-layer curated subset).
-- Source of truth for this app — independent of minicore.transaction_codes.
-- Label casing follows types.ts (title case), not minicore (ALL CAPS).

